mapper.select:


    1=1
    and (JF.DWDM = #{req.deptId} or JF.DWDM IN ( SELECT t.dept_id FROM sys_dept t WHERE find_in_set(#{req.deptId},
        ancestors) ))

    and ( JF.DJXH = #{req.djxh}
    and JF.SHXYDM = #{req.nsrsbh}
    and JF.SHXYDM = #{req.shxydm}
    and JF.NSRMC like concat('%', #{req.nsrmc}, '%')
    and JF.ZGSWJ_DM = #{req.zgswjDm}
    and JF.SKSSQQ >= #{req.skssqq}
    and JF.SKSSQZ <= #{req.skssqz}
    and JF.RKRQ between #{req.beginRkrq} and #{req.endRkrq}

GROUP BY
jf.DWDM,
jf.DEPT_ID,
jf.ZGSWJ_DM,
date_format(`jf`.`RKRQ`, '%Y')
